// learner_quotes.js — Daily LLM-personalized "confidence boost" quotes for TutorX
// (Goja ES5, no Node built-ins, no global-scope state).
//
// Every day, each learner gets one FRESH motivational line generated by the
// LLM and tuned to their chosen prep style (persona) + exam + target score —
// e.g. the "Confidence boost / We'll turn nerves into a higher score" persona.
//
// Economy (fair, scarcity-based — see LT_PRICES below):
//   • The FIRST quote of the day is FREE (it's a retention hook).
//   • Regenerating / asking for an extra quote the same day costs coins.
//   • An on-demand AI "pep talk" (longer coaching) costs more.
// All coin deductions are server-authoritative via the shared game wallet
// (collection "wallets", currencies.game) — the same balance TutorX displays.
//
// RPCs:
//   lt_daily_quote  ← { persona, exam, target, lang, regenerate, gameId }
//                   → { success, quote, sub, persona, exam, date, cached,
//                       provider, coins_spent, coinBalance }
//   lt_pep_talk     ← { persona, exam, target, topic, lang, gameId }
//                   → { success, text, coins_spent, coinBalance }
//   lt_pricing_get  → { success, prices:{...}, currency:"coins" }
//
// Storage: collection "qv_daily_quote", key "q_<YYYY-MM-DD>", owner-read(1)
//          server-write(0). One LLM call per learner per day (cost control).
//
// Cross-module globals reused (defined elsewhere in the merged bundle):
//   callLLM(nk, logger, ctx, systemPrompt, userMessage, maxTokens)  — ai_player.js
//   getGameWallet / deductGameWallet                                — legacy_runtime.js

// ============================================================================
// CONSTANTS
// ============================================================================

var LQ_COLLECTION = "qv_daily_quote";
var LQ_DEFAULT_GAME_ID = "126bf539-dae2-4bcf-964d-316c0fa1f92b"; // QuizVerse / TutorX

// Central fair price table (coins). Anchored to existing economy:
//   tutor AI message = 25 (3 free/day), chatbox = 5/10, cricket = 15-50.
// Retention basics are FREE; only AI-compute extras cost coins.
var LT_PRICES = {
    daily_confidence_quote: 0,   // first quote of the day — free
    daily_quote_regenerate: 5,   // extra / refreshed quote same day
    ai_pep_talk: 10,             // longer on-demand coaching message
    reminder_set: 0,             // setting a study reminder — free
    reminder_smart_plan: 0,      // 2357 spaced-repetition preset — free
    push_optin: 0               // turning on reminders/push — free
};

// Persona → coaching tone. Mirrors _QV_PERSONAS on the TutorX client so the
// LLM voice matches what the learner picked in onboarding.
var LQ_PERSONA_TONE = {
    crunch: "Test is very soon. Be punchy, urgent, focused on high-yield wins and composure under time pressure.",
    steady: "Months to prepare. Be calm and consistency-focused — small daily gains compounding.",
    runway: "Lots of runway / exploring. Be encouraging about habit-building and curiosity over speed.",
    boost:  "Retaking to beat a previous score. Turn nerves into fuel — emphasize that anxiety is energy and a higher score is in reach."
};

// Curated daily fallbacks per persona (used if the LLM is unavailable). Indexed
// by day-of-year so the fallback still varies day to day. Never blank.
var LQ_FALLBACK = {
    crunch: [
        { quote: "You don't need more time — you need your next 20 minutes.", sub: "Hit one weak topic now." },
        { quote: "Pressure is just proof this matters. Channel it.", sub: "Breathe, then begin." },
        { quote: "Cram smart: review what you keep missing, skip what you've mastered.", sub: "High-yield only today." },
        { quote: "Calm hands, sharp mind. You've prepared for this.", sub: "One question at a time." }
    ],
    steady: [
        { quote: "A little every day beats a frantic night.", sub: "Today's 15 minutes count." },
        { quote: "Consistency is a score multiplier. Keep the streak.", sub: "Show up, that's the win." },
        { quote: "You're building something. Add one brick today.", sub: "Small reps, big results." },
        { quote: "Future-you is grateful for the rep you do now.", sub: "Stack another good day." }
    ],
    runway: [
        { quote: "Curiosity now becomes confidence later.", sub: "Explore one new idea." },
        { quote: "Habits beat heroics. Make today easy and repeatable.", sub: "Just start small." },
        { quote: "You have time — use it to fall in love with learning.", sub: "Enjoy the climb." },
        { quote: "The best prep doesn't feel like cramming. It feels like play.", sub: "Have fun today." }
    ],
    boost: [
        { quote: "Nerves mean you care. Let's turn them into a higher score.", sub: "You've grown since last time." },
        { quote: "Last attempt was data, not a verdict. Today is the rewrite.", sub: "Fix one weak spot." },
        { quote: "The version of you that retakes is already stronger.", sub: "Prove it to yourself." },
        { quote: "Beat your old score by beating one old mistake.", sub: "Target your misses." }
    ],
    "": [
        { quote: "Small steps today, big score tomorrow.", sub: "Begin with one question." },
        { quote: "Progress, not perfection. Just keep going.", sub: "You've got this." },
        { quote: "Every expert was once a beginner who didn't quit.", sub: "Keep showing up." },
        { quote: "Your future score is built one rep at a time.", sub: "Start now." }
    ]
};

// ============================================================================
// HELPERS
// ============================================================================

function lqOk(obj) { obj = obj || {}; obj.success = true; return JSON.stringify(obj); }
function lqErr(msg, extra) {
    var o = extra || {};
    o.success = false;
    o.error = msg || "error";
    return JSON.stringify(o);
}

function lqDateKey() {
    var d = new Date();
    var mm = d.getUTCMonth() + 1;
    var dd = d.getUTCDate();
    return d.getUTCFullYear() + "-" + (mm < 10 ? "0" : "") + mm + "-" + (dd < 10 ? "0" : "") + dd;
}

function lqDayOfYear() {
    var now = new Date();
    var start = Date.UTC(now.getUTCFullYear(), 0, 0);
    var diff = Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()) - start;
    return Math.floor(diff / 86400000);
}

function lqStr(v, max) {
    if (v == null) return "";
    var s = String(v).replace(/[\r\n\t]+/g, " ");
    if (max && s.length > max) s = s.substring(0, max);
    return s;
}

function lqPersonaKey(p) {
    p = String(p || "").toLowerCase();
    return LQ_PERSONA_TONE[p] ? p : "";
}

function lqFallback(personaKey) {
    var arr = LQ_FALLBACK[personaKey] || LQ_FALLBACK[""];
    var idx = lqDayOfYear() % arr.length;
    var f = arr[idx];
    return { quote: f.quote, sub: f.sub };
}

// Best-effort JSON extraction from an LLM reply (handles ```json fences / prose).
function lqParseQuote(text) {
    if (!text) return null;
    var s = String(text);
    var a = s.indexOf("{");
    var b = s.lastIndexOf("}");
    if (a < 0 || b <= a) return null;
    var frag = s.substring(a, b + 1);
    try {
        var obj = JSON.parse(frag);
        var q = lqStr(obj.quote || obj.text || "", 180);
        if (!q) return null;
        return { quote: q, sub: lqStr(obj.sub || obj.subtitle || "", 90) };
    } catch (e) { return null; }
}

function lqReadCache(nk, uid, dateKey) {
    try {
        var recs = nk.storageRead([{ collection: LQ_COLLECTION, key: "q_" + dateKey, userId: uid }]);
        if (recs && recs.length > 0 && recs[0].value && recs[0].value.quote) return recs[0].value;
    } catch (e) { /* default */ }
    return null;
}

function lqWriteCache(nk, uid, dateKey, value) {
    try {
        nk.storageWrite([{
            collection: LQ_COLLECTION, key: "q_" + dateKey, userId: uid,
            value: value, permissionRead: 1, permissionWrite: 0
        }]);
    } catch (e) { /* non-fatal */ }
}

// Read the learner's current coin balance from the shared game wallet.
function lqCoinBalance(nk, logger, uid, gameId) {
    try {
        if (typeof getGameWallet === "function") {
            var w = getGameWallet(nk, logger, uid, gameId);
            return (w && w.currencies && (w.currencies.game || w.currencies.tokens)) || 0;
        }
    } catch (e) { /* fall through */ }
    return 0;
}

// Server-authoritative coin charge. Returns { ok, balance, error }.
function lqCharge(nk, logger, uid, gameId, amount, reason) {
    if (!amount || amount <= 0) return { ok: true, balance: lqCoinBalance(nk, logger, uid, gameId) };
    if (typeof deductGameWallet !== "function") {
        return { ok: false, balance: 0, error: "wallet_unavailable" };
    }
    var res = deductGameWallet(nk, logger, uid, gameId, amount, reason);
    if (res && res.success) return { ok: true, balance: res.newBalance };
    return { ok: false, balance: (res && res.currentBalance) || 0, error: (res && res.error) || "deduct_failed" };
}

// Build the LLM system + user prompts for a daily quote.
function lqBuildPrompts(personaKey, exam, target, lang, dateKey, regenerate) {
    var tone = LQ_PERSONA_TONE[personaKey] || "Be warm, specific and motivating for an exam learner.";
    var examTxt = exam ? ("They are preparing for: " + exam + ".") : "They are a general learner.";
    var targetTxt = target ? ("Their target score/goal: " + target + ".") : "";
    var langTxt = (lang && lang !== "en") ? (" Write the response in this language code: " + lang + ".") : "";
    var variety = regenerate ? " Give a DIFFERENT angle than a typical opener — surprise them." : "";

    var system =
        "You are a calm, sharp exam-prep confidence coach. " +
        "Write ONE short, original motivational line for a student, plus a tiny supporting subtitle. " +
        "Voice: " + tone + " " +
        "Rules: max 18 words for the quote, max 10 words for the subtitle, second person ('you'), " +
        "no hashtags, no emojis, no attribution to famous people, no clichés like 'believe in yourself'. " +
        "Be specific to exam prep and the day. Return ONLY compact JSON: {\"quote\":\"...\",\"sub\":\"...\"}." +
        langTxt;

    var user =
        examTxt + " " + targetTxt + " " +
        "Today's date is " + dateKey + " — make it feel fresh for today." + variety +
        " Return only the JSON object.";

    return { system: system, user: user };
}

// ============================================================================
// RPCs
// ============================================================================

function rpcLtDailyQuote(ctx, logger, nk, payload) {
    var uid = ctx.userId;
    if (!uid) return lqErr("no_user");

    var data = {};
    try { data = JSON.parse(payload || "{}") || {}; } catch (e) { return lqErr("bad_payload"); }

    var gameId = lqStr(data.gameId, 64) || LQ_DEFAULT_GAME_ID;
    var personaKey = lqPersonaKey(data.persona);
    var exam = lqStr(data.exam, 80);
    var target = lqStr(data.target, 40);
    var lang = lqStr(data.lang, 12) || "en";
    var regenerate = data.regenerate === true || data.regenerate === 1;
    var dateKey = lqDateKey();

    // Served already today and not a paid regenerate → return cached (FREE).
    if (!regenerate) {
        var cached = lqReadCache(nk, uid, dateKey);
        if (cached) {
            return lqOk({
                quote: cached.quote, sub: cached.sub || "", persona: cached.persona || personaKey,
                exam: cached.exam || exam, date: dateKey, cached: true,
                provider: cached.provider || "cache", coins_spent: 0,
                coinBalance: lqCoinBalance(nk, logger, uid, gameId)
            });
        }
    }

    // Regenerate is a paid AI-compute extra — charge before spending the LLM call.
    var coinsSpent = 0;
    if (regenerate) {
        var price = LT_PRICES.daily_quote_regenerate;
        var charge = lqCharge(nk, logger, uid, gameId, price, "lt_quote_regenerate");
        if (!charge.ok) {
            return lqErr("insufficient_coins", {
                required: price, coinBalance: charge.balance, cost: price
            });
        }
        coinsSpent = price;
    }

    // Generate via LLM with a graceful curated fallback.
    var quoteObj = null, provider = "fallback";
    try {
        if (typeof callLLM === "function") {
            var p = lqBuildPrompts(personaKey, exam, target, lang, dateKey, regenerate);
            var result = callLLM(nk, logger, ctx, p.system, p.user, 150);
            if (result && result.success && result.text) {
                quoteObj = lqParseQuote(result.text);
                if (quoteObj) provider = result.provider || "llm";
            }
        }
    } catch (e) { logger.warn("[Quotes] LLM error: " + e); }

    if (!quoteObj) quoteObj = lqFallback(personaKey);

    var value = {
        date: dateKey, persona: personaKey, exam: exam,
        quote: quoteObj.quote, sub: quoteObj.sub || "",
        provider: provider, generatedAt: Date.now()
    };
    lqWriteCache(nk, uid, dateKey, value);

    return lqOk({
        quote: value.quote, sub: value.sub, persona: personaKey, exam: exam,
        date: dateKey, cached: false, provider: provider,
        coins_spent: coinsSpent, coinBalance: lqCoinBalance(nk, logger, uid, gameId)
    });
}

function rpcLtPepTalk(ctx, logger, nk, payload) {
    var uid = ctx.userId;
    if (!uid) return lqErr("no_user");

    var data = {};
    try { data = JSON.parse(payload || "{}") || {}; } catch (e) { return lqErr("bad_payload"); }

    var gameId = lqStr(data.gameId, 64) || LQ_DEFAULT_GAME_ID;
    var personaKey = lqPersonaKey(data.persona);
    var exam = lqStr(data.exam, 80);
    var target = lqStr(data.target, 40);
    var topic = lqStr(data.topic, 120);
    var lang = lqStr(data.lang, 12) || "en";

    var price = LT_PRICES.ai_pep_talk;
    var charge = lqCharge(nk, logger, uid, gameId, price, "lt_pep_talk");
    if (!charge.ok) {
        return lqErr("insufficient_coins", { required: price, coinBalance: charge.balance, cost: price });
    }

    var tone = LQ_PERSONA_TONE[personaKey] || "Be warm, specific and motivating for an exam learner.";
    var langTxt = (lang && lang !== "en") ? (" Respond in language code: " + lang + ".") : "";
    var system =
        "You are an encouraging, practical exam-prep coach. Voice: " + tone + " " +
        "Give a short pep talk (3-4 sentences) that calms nerves AND gives one concrete next action. " +
        "Second person, no emojis, no clichés." + langTxt;
    var user =
        (exam ? ("Exam: " + exam + ". ") : "") +
        (target ? ("Target: " + target + ". ") : "") +
        (topic ? ("They're worried about: " + topic + ". ") : "They feel nervous about their prep. ") +
        "Write the pep talk now.";

    var text = "", provider = "fallback";
    try {
        if (typeof callLLM === "function") {
            var result = callLLM(nk, logger, ctx, system, user, 320);
            if (result && result.success && result.text) {
                text = lqStr(result.text, 700);
                provider = result.provider || "llm";
            }
        }
    } catch (e) { logger.warn("[Quotes] pep_talk LLM error: " + e); }

    if (!text) {
        text = "Take one breath. The nerves you feel are energy that you can point at the next problem. " +
               "Pick one topic you keep missing and do five questions on it right now — momentum beats worry. " +
               "You're more ready than the anxious voice says.";
    }

    return lqOk({ text: text, provider: provider, coins_spent: price, coinBalance: charge.balance });
}

function rpcLtPricingGet(ctx, logger, nk, payload) {
    return lqOk({ prices: LT_PRICES, currency: "coins" });
}

// ============================================================================
// MODULE INIT
// ============================================================================

function InitModule(ctx, logger, nk, initializer) {
    initializer.registerRpc("lt_daily_quote", rpcLtDailyQuote);
    initializer.registerRpc("lt_pep_talk", rpcLtPepTalk);
    initializer.registerRpc("lt_pricing_get", rpcLtPricingGet);
    logger.info("[Quotes] Registered RPCs: lt_daily_quote, lt_pep_talk, lt_pricing_get");
}
